public final class BankingService {
    private let store: AccountStoreProtocol
    private let queue = DispatchQueue(label: "com.example.banking.service", qos: .userInitiated)

    public init(store: AccountStoreProtocol = SecureAccountStore()) {
        self.store = store
    }

    public func openAccount(holderName: String, accountNumberMasked: String, openingBalance: Money) throws -> Account {
        let account = Account(holderName: holderName, accountNumberMasked: accountNumberMasked, balance: openingBalance)
        try store.createAccount(account)
        if openingBalance.minorUnits > 0 {
            let transaction = Transaction(type: .deposit, accountId: account.id, amount: openingBalance, memo: "Opening balance")
            try store.saveTransactions([transaction])
        }
        return account
    }

    public func getAccount(id: UUID) throws -> Account {
        try store.fetchAccount(id: id)
    }

    public func getAllAccounts() throws -> [Account] {
        try store.fetchAllAccounts()
    }

    public func getTransactions(for accountId: UUID) throws -> [Transaction] {
        try store.fetchTransactions(for: accountId)
    }

    public func deposit(accountId: UUID, amount: Money, memo: String? = nil) throws -> Account {
        guard amount.isPositive else { throw BankingError.invalidAmount }
        return try queue.sync {
            var account = try store.fetchAccount(id: accountId)
            guard account.currencyCode == amount.currencyCode else { throw BankingError.invalidCurrency }
            account.balance = account.balance + amount
            try store.updateAccount(account)
            let transaction = Transaction(type: .deposit, accountId: accountId, amount: amount, memo: memo)
            try store.saveTransactions([transaction])
            return account
        }
    }

    public func withdraw(accountId: UUID, amount: Money, memo: String? = nil) throws -> Account {
        guard amount.isPositive else { throw BankingError.invalidAmount }
        return try queue.sync {
            var account = try store.fetchAccount(id: accountId)
            guard account.currencyCode == amount.currencyCode else { throw BankingError.invalidCurrency }
            guard account.balance.minorUnits >= amount.minorUnits else { throw BankingError.insufficientFunds }
            account.balance = account.balance - amount
            try store.updateAccount(account)
            let transaction = Transaction(type: .withdrawal, accountId: accountId, amount: amount, memo: memo)
            try store.saveTransactions([transaction])
            return account
        }
    }

    public func transfer(from sourceId: UUID, to destinationId: UUID, amount: Money, memo: String? = nil) throws -> (source: Account, destination: Account) {
        guard sourceId != destinationId else { throw BankingError.sameAccountTransfer }
        guard amount.isPositive else { throw BankingError.invalidAmount }

        return try queue.sync {
            var source = try store.fetchAccount(id: sourceId)
            var destination = try store.fetchAccount(id: destinationId)

            guard source.currencyCode == amount.currencyCode, destination.currencyCode == amount.currencyCode else {
                throw BankingError.invalidCurrency
            }

            guard source.balance.minorUnits >= amount.minorUnits else {
                throw BankingError.insufficientFunds
            }

            source.balance = source.balance - amount
            destination.balance = destination.balance + amount

            try store.updateAccount(source)
            try store.updateAccount(destination)

            let outTransaction = Transaction(
                type: .transferOut,
                accountId: sourceId,
                relatedAccountId: destinationId,
                amount: amount,
                memo: memo
            )

            let inTransaction = Transaction(
                type: .transferIn,
                accountId: destinationId,
                relatedAccountId: sourceId,
                amount: amount,
                memo: memo
            )

            try store.saveTransactions([outTransaction, inTransaction])

            return (source, destination)
        }
    }
