            accountNumberMasked: "•••• 1024",
            openingBalance: try Money(minorUnits: 250_000, currencyCode: "USD")
        )

        let savings = try service.openAccount(
            holderName: "Alex Johnson",
            accountNumberMasked: "•••• 7781",
            openingBalance: try Money(minorUnits: 1_500_000, currencyCode: "USD")
        )

        _ = try service.deposit(
            accountId: checking.id,
            amount: try Money(minorUnits: 50_00, currencyCode: "USD"),
            memo: "Paycheck adjustment"
        )

        _ = try service.withdraw(
            accountId: checking.id,
            amount: try Money(minorUnits: 20_00, currencyCode: "USD"),
            memo: "ATM withdrawal"
        )

        _ = try service.transfer(
            from: savings.id,
            to: checking.id,
            amount: try Money(minorUnits: 100_00, currencyCode: "USD"),
            memo: "Monthly transfer"
        )

        return (service, viewModel)
